#include <stdio.h>
#include <stdlib.h>

int T;
int C, V;
int **clauses;
int *assign;

int literal_true(int lit) {
    int var = abs(lit);
    if (assign[var] == 0) return 0;
    if (lit > 0) return assign[var] == 1;
    return assign[var] == -1;
}

int main() {
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &C, &V);
        clauses = (int **)malloc(C * sizeof(int *));
        for (int i = 0; i < C; i++) {
            clauses[i] = (int *)malloc(3 * sizeof(int));
            for (int j = 0; j < 3; j++) {
                scanf("%d", &clauses[i][j]);
            }
        }
        assign = (int *)malloc((V + 1) * sizeof(int));
        for (int i = 1; i <= V; i++) {
            assign[i] = 0;
        }
        for (int i = 0; i < C; i++) {
            int a = clauses[i][0], b = clauses[i][1], c = clauses[i][2];
            if (a > 0 && b > 0 && c > 0) {
                assign[a] = assign[b] = assign[c] = 1;
            } else if (a < 0 && b < 0 && c < 0) {
                assign[-a] = assign[-b] = assign[-c] = -1;
            } else {
                if (a > 0) assign[a] = 1;
                if (b > 0) assign[b] = 1;
                if (c > 0) assign[c] = 1;
                if (a < 0) assign[-a] = -1;
                if (b < 0) assign[-b] = -1;
                if (c < 0) assign[-c] = -1;
            }
        }
        for (int i = 1; i <= V; i++) {
            if (assign[i] == 1) printf("T");
            else printf("F");
        }
        printf("\n");
        free(assign);
        for (int i = 0; i < C; i++) {
            free(clauses[i]);
        }
        free(clauses);
    }
    return 0;
}

